-- points_contract_count initial normalisé: 12
-- La meta finale est recalculée après backfill des anciennes lignes actives et soft-delete.

CREATE EXTENSION IF NOT EXISTS pgcrypto WITH SCHEMA extensions;

CREATE TABLE IF NOT EXISTS public.base_cg_retraite_contracts (
  contract_id text PRIMARY KEY,
  source_id text NOT NULL,
  company text NOT NULL,
  contract_name text NOT NULL,
  contract_type text NOT NULL,
  per_compartment text NULL,
  contract_data jsonb NOT NULL,
  row_hash text NOT NULL,
  is_deleted boolean NOT NULL DEFAULT false,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now(),
  CONSTRAINT base_cg_retraite_contracts_contract_type_chk
    CHECK (contract_type IN ('PERIN', 'PERP', 'MADELIN', 'ARTICLE83', 'PEROB', 'PERCO', 'PERECO', 'PER_POINTS', 'AUTRE')),
  CONSTRAINT base_cg_retraite_contracts_per_compartment_chk
    CHECK (per_compartment IS NULL OR per_compartment IN ('C0', 'C1', 'C1_BIS', 'C2', 'C3'))
);

CREATE TABLE IF NOT EXISTS public.base_cg_retraite_catalog_meta (
  catalog_key text PRIMARY KEY,
  schema_version text NOT NULL,
  contract_count integer NOT NULL,
  document_count integer NOT NULL,
  points_contract_count integer NOT NULL,
  canonical_hash text NOT NULL,
  generated_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_base_cg_retraite_contracts_is_deleted ON public.base_cg_retraite_contracts (is_deleted);
CREATE INDEX IF NOT EXISTS idx_base_cg_retraite_contracts_company ON public.base_cg_retraite_contracts (company);
CREATE INDEX IF NOT EXISTS idx_base_cg_retraite_contracts_type ON public.base_cg_retraite_contracts (contract_type);
CREATE INDEX IF NOT EXISTS idx_base_cg_retraite_contracts_compartment ON public.base_cg_retraite_contracts (per_compartment);

CREATE OR REPLACE FUNCTION public.set_base_cg_retraite_contract_row_hash()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, extensions
AS $$
BEGIN
  NEW.row_hash := encode(extensions.digest(NEW.contract_data::text, 'sha256'), 'hex');
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_base_cg_retraite_contracts_row_hash ON public.base_cg_retraite_contracts;
CREATE TRIGGER trg_base_cg_retraite_contracts_row_hash
  BEFORE INSERT OR UPDATE OF contract_data ON public.base_cg_retraite_contracts
  FOR EACH ROW
  EXECUTE FUNCTION public.set_base_cg_retraite_contract_row_hash();

DROP TRIGGER IF EXISTS trg_base_cg_retraite_contracts_updated_at ON public.base_cg_retraite_contracts;
CREATE TRIGGER trg_base_cg_retraite_contracts_updated_at
  BEFORE UPDATE ON public.base_cg_retraite_contracts
  FOR EACH ROW
  EXECUTE FUNCTION public.set_updated_at_base_cg_retraite();

ALTER TABLE public.base_cg_retraite_contracts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.base_cg_retraite_catalog_meta ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "base_cg_retraite_contracts_select_auth" ON public.base_cg_retraite_contracts;
DROP POLICY IF EXISTS "base_cg_retraite_contracts_insert_admin" ON public.base_cg_retraite_contracts;
DROP POLICY IF EXISTS "base_cg_retraite_contracts_update_admin" ON public.base_cg_retraite_contracts;
DROP POLICY IF EXISTS "base_cg_retraite_contracts_delete_admin" ON public.base_cg_retraite_contracts;
CREATE POLICY "base_cg_retraite_contracts_select_auth"
  ON public.base_cg_retraite_contracts
  FOR SELECT TO authenticated
  USING (true);
CREATE POLICY "base_cg_retraite_contracts_insert_admin"
  ON public.base_cg_retraite_contracts
  FOR INSERT TO authenticated
  WITH CHECK ((select public.is_admin()));
CREATE POLICY "base_cg_retraite_contracts_update_admin"
  ON public.base_cg_retraite_contracts
  FOR UPDATE TO authenticated
  USING ((select public.is_admin()))
  WITH CHECK ((select public.is_admin()));
CREATE POLICY "base_cg_retraite_contracts_delete_admin"
  ON public.base_cg_retraite_contracts
  FOR DELETE TO authenticated
  USING ((select public.is_admin()));

DROP POLICY IF EXISTS "base_cg_retraite_catalog_meta_select_auth" ON public.base_cg_retraite_catalog_meta;
DROP POLICY IF EXISTS "base_cg_retraite_catalog_meta_insert_admin" ON public.base_cg_retraite_catalog_meta;
DROP POLICY IF EXISTS "base_cg_retraite_catalog_meta_update_admin" ON public.base_cg_retraite_catalog_meta;
DROP POLICY IF EXISTS "base_cg_retraite_catalog_meta_delete_admin" ON public.base_cg_retraite_catalog_meta;
CREATE POLICY "base_cg_retraite_catalog_meta_select_auth"
  ON public.base_cg_retraite_catalog_meta
  FOR SELECT TO authenticated
  USING (true);

GRANT SELECT ON public.base_cg_retraite_contracts TO authenticated;
GRANT INSERT, UPDATE, DELETE ON public.base_cg_retraite_contracts TO authenticated;
REVOKE INSERT, UPDATE, DELETE ON public.base_cg_retraite_catalog_meta FROM authenticated;
GRANT SELECT ON public.base_cg_retraite_catalog_meta TO authenticated;

