ON CONFLICT (contract_id) DO UPDATE SET
  source_id = excluded.source_id,
  company = excluded.company,
  contract_name = excluded.contract_name,
  contract_type = excluded.contract_type,
  per_compartment = excluded.per_compartment,
  contract_data = excluded.contract_data,
  row_hash = excluded.row_hash,
  is_deleted = excluded.is_deleted,
  updated_at = now();

-- Parité additive avec les anciennes lignes admin déjà migrées dans base_cg_retraite_overrides :
-- les contrats PDF-only ou corrigés par SQL sont copiés avant la FK documents -> contracts.
INSERT INTO public.base_cg_retraite_contracts (
  contract_id,
  source_id,
  company,
  contract_name,
  contract_type,
  per_compartment,
  contract_data,
  row_hash,
  is_deleted,
  updated_at
)
SELECT
  contract_id,
  coalesce(contract_data ->> 'sourceId', contract_id),
  coalesce(contract_data ->> 'compagnie', 'NON_RENSEIGNEE'),
  coalesce(contract_data ->> 'nomContrat', contract_id),
  CASE
    WHEN contract_data ->> 'typeContrat' IN ('PERIN', 'PERP', 'MADELIN', 'ARTICLE83', 'PEROB', 'PERCO', 'PERECO', 'PER_POINTS', 'AUTRE')
      THEN contract_data ->> 'typeContrat'
    ELSE 'AUTRE'
  END,
  CASE
    WHEN contract_data ->> 'perCompartment' IN ('C0', 'C1', 'C1_BIS', 'C2', 'C3')
      THEN contract_data ->> 'perCompartment'
    ELSE NULL
  END,
  contract_data - 'documents',
  encode(extensions.digest((contract_data - 'documents')::text, 'sha256'), 'hex'),
  false,
  coalesce(updated_at, now())
FROM public.base_cg_retraite_overrides
WHERE is_deleted IS DISTINCT FROM true
ON CONFLICT (contract_id) DO UPDATE SET
  source_id = excluded.source_id,
  company = excluded.company,
  contract_name = excluded.contract_name,
  contract_type = excluded.contract_type,
  per_compartment = excluded.per_compartment,
  contract_data = excluded.contract_data,
  row_hash = excluded.row_hash,
  is_deleted = excluded.is_deleted,
  updated_at = now();

UPDATE public.base_cg_retraite_contracts AS contracts
SET is_deleted = true,
    updated_at = now()
FROM public.base_cg_retraite_overrides AS overrides
WHERE overrides.contract_id = contracts.contract_id
  AND overrides.is_deleted IS true;

UPDATE public.base_cg_retraite_contracts
SET row_hash = encode(extensions.digest(contract_data::text, 'sha256'), 'hex')
WHERE row_hash IS DISTINCT FROM encode(extensions.digest(contract_data::text, 'sha256'), 'hex');

ALTER TABLE public.base_cg_retraite_documents
  DROP CONSTRAINT IF EXISTS base_cg_retraite_documents_contract_id_fkey;
ALTER TABLE public.base_cg_retraite_documents
  ADD CONSTRAINT base_cg_retraite_documents_contract_id_fkey
  FOREIGN KEY (contract_id) REFERENCES public.base_cg_retraite_contracts(contract_id)
  ON UPDATE CASCADE ON DELETE RESTRICT;

CREATE OR REPLACE FUNCTION public.refresh_base_cg_retraite_catalog_meta()
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, extensions
AS $$
BEGIN
  WITH active_contracts AS (
    SELECT
      contract_id,
      source_id,
      company,
      contract_name,
      contract_type,
      per_compartment,
      contract_data,
      row_hash
    FROM public.base_cg_retraite_contracts
    WHERE is_deleted IS false
  ),
  catalog AS (
    SELECT
      count(*)::integer AS contract_count,
      count(*) FILTER (
        WHERE contract_data -> 'pointsParams' IS NOT NULL
          AND contract_data -> 'pointsParams' <> 'null'::jsonb
      )::integer AS points_contract_count,
      encode(
        extensions.digest(
          coalesce(
            string_agg(
              contract_id || E'\t' ||
              source_id || E'\t' ||
              company || E'\t' ||
              contract_name || E'\t' ||
              contract_type || E'\t' ||
              coalesce(per_compartment, '') || E'\t' ||
              row_hash,
              E'\n'
              ORDER BY contract_id
            ),
            ''
          ),
          'sha256'
        ),
        'hex'
      ) AS canonical_hash
    FROM active_contracts
  )
  INSERT INTO public.base_cg_retraite_catalog_meta (
    catalog_key, schema_version, contract_count, document_count, points_contract_count, canonical_hash
  )
  SELECT
    'base-cg-retraite',
    '2025-01-base-cg-retraite',
    catalog.contract_count,
    (
      SELECT count(*)::integer
      FROM public.base_cg_retraite_documents
    ),
    catalog.points_contract_count,
    catalog.canonical_hash
  FROM catalog
  ON CONFLICT (catalog_key) DO UPDATE SET
    schema_version = excluded.schema_version,
    contract_count = excluded.contract_count,
    document_count = excluded.document_count,
    points_contract_count = excluded.points_contract_count,
    canonical_hash = excluded.canonical_hash,
    generated_at = now();
END;
$$;

SELECT public.refresh_base_cg_retraite_catalog_meta();

CREATE OR REPLACE FUNCTION public.refresh_base_cg_retraite_catalog_meta_trigger()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, extensions
AS $$
BEGIN
  PERFORM public.refresh_base_cg_retraite_catalog_meta();
  RETURN NULL;
END;
$$;

DROP TRIGGER IF EXISTS trg_base_cg_retraite_contracts_refresh_meta ON public.base_cg_retraite_contracts;
CREATE TRIGGER trg_base_cg_retraite_contracts_refresh_meta
  AFTER INSERT OR UPDATE OR DELETE ON public.base_cg_retraite_contracts
  FOR EACH STATEMENT
  EXECUTE FUNCTION public.refresh_base_cg_retraite_catalog_meta_trigger();

DROP TRIGGER IF EXISTS trg_base_cg_retraite_documents_refresh_meta ON public.base_cg_retraite_documents;
CREATE TRIGGER trg_base_cg_retraite_documents_refresh_meta
  AFTER INSERT OR UPDATE OR DELETE ON public.base_cg_retraite_documents
  FOR EACH STATEMENT
  EXECUTE FUNCTION public.refresh_base_cg_retraite_catalog_meta_trigger();
